import{_ as a,o as i,c as t,ae as s}from"./chunks/framework.BGHOrOyn.js";const c=JSON.parse('{"title":"Changing /dev/hidraw permissions","description":"https://askubuntu.com/a/15643/593957","frontmatter":{"description":"https://askubuntu.com/a/15643/593957"},"headers":[],"relativePath":"software-engineering/linux/udev-rules/changing-dev-hidraw-permissions.md","filePath":"software-engineering/linux/udev-rules/changing-dev-hidraw-permissions.md"}'),n={name:"software-engineering/linux/udev-rules/changing-dev-hidraw-permissions.md"};function o(r,e,d,u,l,p){return i(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="changing-dev-hidraw-permissions" tabindex="-1">Changing /dev/hidraw permissions <a class="header-anchor" href="#changing-dev-hidraw-permissions" aria-label="Permalink to &quot;Changing /dev/hidraw permissions&quot;">​</a></h1><p>I gave up running around trying to figure out some other means of doing it than udev rules, and instead just learned a bit about udev and wrote a flippin&#39; rule. The following line was placed in a <code>.rules</code> file (I named mine <code>99-hidraw-permissions.rules</code>) located under <code>/etc/udev/rules.d</code>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>KERNEL==&quot;hidraw*&quot;, SUBSYSTEM==&quot;hidraw&quot;, MODE=&quot;0664&quot;, GROUP=&quot;plugdev&quot;</span></span></code></pre></div><p>Basically this assigns all devices coming out of the hidraw subsystem in the kernel to the group <code>plugdev</code> and sets the permissions to r/w r/w r (for root [the default owner], plugdev, and everyone else respectively). With myself added to the plugdev group, everything&#39;s dandy.</p><p>Not quite as brain melting as I&#39;d expected. Udev rules actually seem pretty straightforward... I mean, they look like they <em>can</em> get ridiculous if you&#39;re dealing with individual product IDs and whatnot, but they seem pretty damn tame for what they do.</p>',5)])])}const g=a(n,[["render",o]]);export{c as __pageData,g as default};
